export type PlayerColor = 'red' | 'green' | 'yellow' | 'blue';

export interface Token {
  id: string;
  player: PlayerColor;
  index: number; // 0 to 3
  position: number; // -1 for home, 0-51 for common path, 52-57 for home stretch, 58 for finish
  isFinished: boolean;
}

export interface Player {
  id: PlayerColor;
  name: string;
  color: string;
  tokens: Token[];
  isBot: boolean;
  isActive: boolean;
  score: number;
}

export interface GameState {
  players: Player[];
  activePlayerIndex: number;
  diceValue: number | null;
  isRolling: boolean;
  moveInProgress: boolean;
  gameStatus: 'waiting' | 'rolling' | 'moving' | 'finished';
  winner: PlayerColor | null;
  logs: string[];
  lastDiceRoll: number | null;
}

import { PlayerColor } from './types';

export const BOARD_SIZE = 15; // 15x15 grid

// Common path coordinates (52 steps)
// Starting from Red's entry point (tile 1)
export const COMMON_PATH = [
  { r: 6, c: 1 }, { r: 6, c: 2 }, { r: 6, c: 3 }, { r: 6, c: 4 }, { r: 6, c: 5 }, // Red area path
