// Home base (initial) positions for tokens
export const HOME_BASES: Record<PlayerColor, { r: number, c: number }[]> = {
  red: [{ r: 2, c: 2 }, { r: 2, c: 3 }, { r: 3, c: 2 }, { r: 3, c: 3 }],
