export const SAFE_POSITIONS = [0, 8, 13, 21, 26, 34, 39, 47];

export const COLORS = {
  red: '#ff4b5c',
  green: '#2ecc71',
  yellow: '#f1c40f',
  blue: '#3498db',
  bg: '#1a1a2e'
};

import { create } from 'https://esm.sh/zustand';
import { GameState, PlayerColor, Token, Player } from '../types';
import { START_POSITIONS, HOME_STRETCH_ENTRY, SAFE_POSITIONS } from '../constants.tsx';

interface GameStore extends GameState {
  rollDice: () => void;
  moveToken: (tokenId: string) => Promise<void>;
  resetGame: () => void;
  nextTurn: (force?: boolean) => void;
  setBot: (color: PlayerColor, isBot: boolean) => void;
}

const initialPlayers: Player[] = [
  { id: 'red', name: 'Player 1', color: 'red', tokens: createTokens('red'), isBot: false, isActive: true, score: 0 },
  { id: 'green', name: 'Player 2', color: 'green', tokens: createTokens('green'), isBot: true, isActive: false, score: 0 },
  { id: 'yellow', name: 'Player 3', color: 'yellow', tokens: createTokens('yellow'), isBot: true, isActive: false, score: 0 },
  { id: 'blue', name: 'Player 4', color: 'blue', tokens: createTokens('blue'), isBot: true, isActive: false, score: 0 },
];

function createTokens(player: PlayerColor): Token[] {
  return Array.from({ length: 4 }).map((_, i) => ({
    id: `${player}-${i}`,
    player,
    index: i,
    position: -1,
    isFinished: false
  }));
}

export const useGameStore = create<GameStore>((set, get) => ({
  players: initialPlayers,
  activePlayerIndex: 0,
  diceValue: null,
  isRolling: false,
  moveInProgress: false,
  gameStatus: 'rolling',
  winner: null,
  logs: ['Welcome to Ludo Taste!'],
  lastDiceRoll: null,

  setBot: (color, isBot) => set(state => ({
    players: state.players.map(p => p.id === color ? { ...p, isBot } : p)
  })),

  resetGame: () => set({
    players: initialPlayers.map(p => ({ ...p, tokens: createTokens(p.id as PlayerColor), isActive: p.id === 'red' })),
    activePlayerIndex: 0,
    diceValue: null,
    isRolling: false,
    moveInProgress: false,
    gameStatus: 'rolling',
    winner: null,
    logs: ['Game Reset! Ready for a new match.'],
    lastDiceRoll: null,
  }),

  rollDice: () => {
    const { isRolling, gameStatus, players, activePlayerIndex } = get();
    if (isRolling || gameStatus !== 'rolling') return;

    set({ isRolling: true });

    // Dice animation delay
    setTimeout(() => {
      const roll = Math.floor(Math.random() * 6) + 1;
      const player = players[activePlayerIndex];
      const movableTokens = getMovableTokens(player, roll);

      set({ 
        diceValue: roll, 
        lastDiceRoll: roll,
        isRolling: false,
        gameStatus: movableTokens.length > 0 ? 'moving' : 'rolling',
        logs: [`${player.name} rolled a ${roll}`]
      });

      if (movableTokens.length === 0) {
        setTimeout(() => get().nextTurn(), 1000);
      } else if (player.isBot) {
        // Simple Bot logic: pick first movable token
        setTimeout(() => get().moveToken(movableTokens[0].id), 800);
      }
    }, 600);
  },

  moveToken: async (tokenId: string) => {
    const { players, activePlayerIndex, diceValue, gameStatus, moveInProgress } = get();
    if (gameStatus !== 'moving' || moveInProgress || !diceValue) return;

    const currentPlayer = players[activePlayerIndex];
    const tokenIndex = currentPlayer.tokens.findIndex(t => t.id === tokenId);
    if (tokenIndex === -1) return;

    const token = currentPlayer.tokens[tokenIndex];
    const canMove = isValidMove(token, diceValue);
    if (!canMove) return;

    set({ moveInProgress: true });

    let currentPos = token.position;
    const steps = diceValue;

    // Movement animation
    for (let i = 0; i < steps; i++) {
      await new Promise(r => setTimeout(r, 150));
      if (currentPos === -1) {
        currentPos = START_POSITIONS[token.player];
      } else {
        currentPos = getNextPosition(token.player, currentPos);
      }

      set(state => ({
        players: state.players.map((p, idx) => 
          idx === state.activePlayerIndex 
            ? { ...p, tokens: p.tokens.map(t => t.id === tokenId ? { ...t, position: currentPos } : t) }
            : p
        )
      }));
    }

    // Check for kills and finishing
    const finalPos = currentPos;
    const isFinished = finalPos === 58;
    let gotExtraTurn = diceValue === 6 || isFinished;

    // Handle Kills
    let killOccurred = false;
    if (finalPos < 52 && !SAFE_POSITIONS.includes(finalPos)) {
      const state = get();
      const updatedPlayers = state.players.map(p => {
        if (p.id === currentPlayer.id) return p;
        const killedTokens = p.tokens.map(t => {
          if (t.position === finalPos) {
            killOccurred = true;
            return { ...t, position: -1 };
          }
          return t;
        });
        return { ...p, tokens: killedTokens };
      });
      if (killOccurred) {
        gotExtraTurn = true;
        set({ players: updatedPlayers, logs: [...get().logs, "Token Killed! Extra turn!"] });
      }
    }

    if (isFinished) {
      set(state => ({
        players: state.players.map((p, idx) => 
          idx === state.activePlayerIndex 
            ? { ...p, tokens: p.tokens.map(t => t.id === tokenId ? { ...t, isFinished: true, position: 58 } : t) }
            : p
        ),
        logs: [...get().logs, `${currentPlayer.name} finished a token!`]
      }));
    }

    // Check Win Condition
    const updatedPlayer = get().players[activePlayerIndex];
    if (updatedPlayer.tokens.every(t => t.isFinished)) {
      set({ winner: updatedPlayer.id as PlayerColor, gameStatus: 'finished', logs: [...get().logs, `${updatedPlayer.name} WINS!`] });
      return;
    }

    set({ moveInProgress: false, gameStatus: 'rolling' });

    if (!gotExtraTurn) {
      get().nextTurn();
    } else {
      set({ logs: [...get().logs, "Roll again!"] });
      if (updatedPlayer.isBot) {
        setTimeout(() => get().rollDice(), 1000);
      }
    }
  },

  nextTurn: (force = false) => {
    const state = get();
    if (state.moveInProgress && !force) return;

    const nextIdx = (state.activePlayerIndex + 1) % 4;
    set({
      activePlayerIndex: nextIdx,
      diceValue: null,
      gameStatus: 'rolling',
      players: state.players.map((p, i) => ({ ...p, isActive: i === nextIdx }))
    });

    const nextPlayer = get().players[nextIdx];
    if (nextPlayer.isBot) {
      setTimeout(() => get().rollDice(), 1000);
    }
  }
}));

function getMovableTokens(player: Player, dice: number): Token[] {
  return player.tokens.filter(t => !t.isFinished && isValidMove(t, dice));
}

function isValidMove(token: Token, dice: number): boolean {
  if (token.position === -1) return dice === 6;
  if (token.position + dice > 58) return false;
  return true;
}

function getNextPosition(player: PlayerColor, current: number): number {
  if (current === -1) return START_POSITIONS[player];
  if (current < 52) {
    const entry = HOME_STRETCH_ENTRY[player];
    if (current === entry) return 52;
    return (current + 1) % 52;
  }
  return current + 1; // Home stretch moving towards 58
}

import React from 'react';
import { motion } from 'framer-motion';
import { useGameStore } from '../store/useGameStore.ts';

export const Dice: React.FC = () => {
  const { diceValue, isRolling, rollDice, gameStatus, players, activePlayerIndex } = useGameStore();
  const activePlayer = players[activePlayerIndex];

  const getDots = (num: number) => {
    const dots = [];
    for (let i = 0; i < num; i++) dots.push(<div key={i} className="w-2 h-2 bg-current rounded-full" />);
    return dots;
  };

  const getGridClass = (num: number) => {
    switch(num) {
      case 1: return "flex items-center justify-center";
      case 2: return "flex flex-col items-center justify-around";
      case 3: return "flex flex-col items-center justify-between py-1";
      case 4: return "grid grid-cols-2 gap-2 p-2";
      case 5: return "grid grid-cols-2 gap-2 p-2 relative [&>*:last-child]:absolute [&>*:last-child]:top-1/2 [&>*:last-child]:left-1/2 [&>*:last-child]:-translate-x-1/2 [&>*:last-child]:-translate-y-1/2";
      case 6: return "grid grid-cols-2 gap-2 p-2";
      default: return "";
    }
  };

  return (
    <div className="flex flex-col items-center gap-4">
      <motion.div
        animate={isRolling ? { 
          rotateX: [0, 90, 180, 270, 360],
          rotateY: [0, 90, 180, 270, 360],
          scale: [1, 1.2, 1]
        } : { rotate: 0 }}
        transition={{ duration: 0.6, repeat: isRolling ? Infinity : 0 }}
        onClick={() => gameStatus === 'rolling' && !activePlayer.isBot && rollDice()}
        className={`w-16 h-16 rounded-xl shadow-2xl flex items-center justify-center cursor-pointer transition-colors border-b-4 border-black/20
          ${gameStatus === 'rolling' && !activePlayer.isBot ? 'hover:scale-110' : 'opacity-80 cursor-not-allowed'}
          ${activePlayer.id === 'red' ? 'bg-red-500 text-white' : 
            activePlayer.id === 'green' ? 'bg-green-500 text-white' : 
            activePlayer.id === 'yellow' ? 'bg-yellow-500 text-black' : 
            'bg-blue-500 text-white'}`}
      >
        <div className={`w-full h-full ${getGridClass(diceValue || 1)}`}>
          {getDots(diceValue || 1)}
        </div>
      </motion.div>
      <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">
        {isRolling ? "Rolling..." : `Last: ${diceValue || '-'}`}
      </span>
    </div>
  );
};

import React from 'react';
import { motion } from 'framer-motion';
import { useGameStore } from '../store/useGameStore.ts';
import { COMMON_PATH, HOME_STRETCHES, HOME_BASES, SAFE_POSITIONS, BOARD_SIZE } from '../constants.tsx';
import { PlayerColor, Token } from '../types';

const GRID_SIZE = 100 / BOARD_SIZE;

export const LudoBoard: React.FC = () => {
  const { players, diceValue, gameStatus, moveToken } = useGameStore();

  const renderCell = (r: number, c: number) => {
    // Determine cell type and color
    let bgColor = "bg-white";
    let border = "border border-gray-100";

    // Home Bases
    if (r < 6 && c < 6) bgColor = "bg-red-500/10";
    if (r < 6 && c > 8) bgColor = "bg-green-500/10";
    if (r > 8 && c < 6) bgColor = "bg-blue-500/10";
    if (r > 8 && c > 8) bgColor = "bg-yellow-500/10";

    // Home Stretches
    if (r === 7 && c > 0 && c < 7) bgColor = "bg-red-500";
    if (r > 0 && r < 7 && c === 7) bgColor = "bg-green-500";
    if (r === 7 && c > 7 && c < 14) bgColor = "bg-yellow-500";
    if (r > 7 && r < 14 && c === 7) bgColor = "bg-blue-500";

    // Common Path Starts & Safes
    if (r === 6 && c === 1) bgColor = "bg-red-500";
    if (r === 1 && c === 8) bgColor = "bg-green-500";
    if (r === 8 && c === 13) bgColor = "bg-yellow-500";
    if (r === 13 && c === 6) bgColor = "bg-blue-500";

    // Center Triangle (Winning Zone)
    if (r >= 6 && r <= 8 && c >= 6 && c <= 8) {
      if (r === 7 && c === 7) return <div key={`${r}-${c}`} className="relative bg-white flex items-center justify-center font-black text-[8px]">FINISH</div>;
      if (r === 6 && c === 7) bgColor = "bg-green-500";
      if (r === 8 && c === 7) bgColor = "bg-blue-500";
      if (r === 7 && c === 6) bgColor = "bg-red-500";
      if (r === 7 && c === 8) bgColor = "bg-yellow-500";
    }

    return (
      <div 
        key={`${r}-${c}`} 
        className={`${bgColor} ${border} relative overflow-hidden`}
        style={{ width: `${GRID_SIZE}%`, height: `${GRID_SIZE}%` }}
      >
        {SAFE_POSITIONS.some(idx => COMMON_PATH[idx].r === r && COMMON_PATH[idx].c === c) && (
          <div className="absolute inset-0 flex items-center justify-center opacity-20">★</div>
        )}
      </div>
    );
  };

  const getCoordinates = (token: Token) => {
    if (token.position === -1) return HOME_BASES[token.player][token.index];
    if (token.position < 52) return COMMON_PATH[token.position];
    if (token.position < 58) return HOME_STRETCHES[token.player][token.position - 52];
    return { r: 7, c: 7 }; // Finished
  };

  return (
    <div className="relative aspect-square w-full max-w-[600px] bg-white rounded-2xl shadow-2xl overflow-hidden border-8 border-white perspective-1000 rotate-x-12">
      {/* Grid Background */}
      <div className="absolute inset-0 flex flex-wrap">
        {Array.from({ length: BOARD_SIZE }).map((_, r) => (
          Array.from({ length: BOARD_SIZE }).map((_, c) => renderCell(r, c))
        ))}
      </div>

      {/* Tokens */}
      {players.flatMap(p => p.tokens).map(token => {
        const coords = getCoordinates(token);
        const isMovable = gameStatus === 'moving' && !players[useGameStore.getState().activePlayerIndex].isBot && 
                          token.player === players[useGameStore.getState().activePlayerIndex].id && 
                          (token.position === -1 ? diceValue === 6 : token.position + (diceValue || 0) <= 58);

        return (
          <motion.div
            key={token.id}
            initial={false}
            animate={{ 
              top: `${coords.r * GRID_SIZE}%`, 
              left: `${coords.c * GRID_SIZE}%`,
              scale: isMovable ? [1, 1.2, 1] : 1,
              zIndex: isMovable ? 50 : 10
            }}
            transition={{ type: 'spring', damping: 20, stiffness: 200 }}
            onClick={() => isMovable && moveToken(token.id)}
            className={`absolute flex items-center justify-center rounded-full shadow-lg border-2 border-white cursor-pointer
              ${isMovable ? 'ring-4 ring-white ring-offset-2 animate-pulse' : ''}
              ${token.player === 'red' ? 'bg-red-500' : 
                token.player === 'green' ? 'bg-green-500' : 
                token.player === 'yellow' ? 'bg-yellow-500' : 
                'bg-blue-500'}`}
            style={{ 
              width: `${GRID_SIZE * 0.8}%`, 
              height: `${GRID_SIZE * 0.8}%`,
              margin: `${GRID_SIZE * 0.1}%`
            }}
          >
            {token.isFinished ? '✓' : ''}
          </motion.div>
        );
      })}

      {/* Large Home Labels */}
      <div className="absolute top-0 left-0 p-8 font-black text-white/20 text-4xl">RED</div>
      <div className="absolute top-0 right-0 p-8 font-black text-white/20 text-4xl">GREEN</div>
      <div className="absolute bottom-0 left-0 p-8 font-black text-white/20 text-4xl">BLUE</div>
      <div className="absolute bottom-0 right-0 p-8 font-black text-white/20 text-4xl">YELLOW</div>
    </div>
  );
};

